      CREATE OR REPLACE FUNCTION notify_hl7_encounter_discharged()
RETURNS TRIGGER AS $function$
      BEGIN
  -- only when status changed to DISCHARGED
  IF NEW.status = 'DISCHARGED' AND OLD.status IS DISTINCT FROM 'DISCHARGED' THEN

    INSERT INTO ${hl7.integrationSchema}.hl7_event (
      id,
      event_type,
      object_key,
      event_datetime
      )
      VALUES (
      gen_random_uuid()::varchar,
      '${hl7.events.patientDischarged}',
      NEW.id::varchar,
      NOW()
      );

      END IF;

      RETURN NEW;
      END;
      $function$ LANGUAGE plpgsql;


DROP TRIGGER IF EXISTS trg_hl7_encounter_discharged ON patient_encounters;

CREATE TRIGGER trg_hl7_encounter_discharged
  AFTER UPDATE ON patient_encounters
  FOR EACH ROW
  EXECUTE FUNCTION notify_hl7_encounter_discharged();
